 33→impl SpecParser {
 34→    fn parse(&mut self, spec: &Path) {
 35→        let spec_content = fs::read_to_string(spec).unwrap_or_default();
 36→
 37→        self.source_text.clone_from(&spec_content);
 38→
 39→        let allocator = Allocator::default();
 40→        let mut source_type = SourceType::from_path(spec).unwrap_or_default();
 41→        if source_type.is_javascript() {
 42→            source_type = source_type.with_jsx(true);
 43→        }
 44→
 45→        let mut ret = Parser::new(&allocator, &spec_content, source_type).parse();
 46→        assert!(ret.errors.is_empty());
 47→        self.visit_program(&mut ret.program);
 48→    }
