 10→pub enum FormatFileStrategy {
 11→    OxcFormatter {
 12→        path: PathBuf,
 13→        source_type: SourceType,
 14→    },
 15→    /// TOML files formatted by taplo (Pure Rust).
 16→    OxfmtToml {
 17→        path: PathBuf,
 18→    },
 19→    ExternalFormatter {
 20→        path: PathBuf,
 21→        parser_name: &'static str,
 22→    },
 23→    /// `package.json` is special: sorted by `sort-package-json` then formatted by external formatter.
 24→    ExternalFormatterPackageJson {
 25→        path: PathBuf,
 26→        parser_name: &'static str,
 27→    },
 28→}
 29→
 30→impl TryFrom<PathBuf> for FormatFileStrategy {
 31→    type Error = ();
 32→
 33→    fn try_from(path: PathBuf) -> Result<Self, Self::Error> {
 34→        // Check JS/TS files first
 35→        // TODO: This logic should(can) move to this file, after LSP support is also moved here.
 36→        if let Some(source_type) = get_supported_source_type(&path) {
 37→            return Ok(Self::OxcFormatter { path, source_type });
 38→        }
 39→
 40→        // Extract file_name and extension once for all subsequent checks
 41→        let Some(file_name) = path.file_name().and_then(|f| f.to_str()) else {
 42→            return Err(());
 43→        };
 44→
 45→        // Excluded files like lock files
 46→        if EXCLUDE_FILENAMES.contains(file_name) {
 47→            return Err(());
 48→        }
 49→
 50→        // Then TOML files
 51→        if is_toml_file(file_name) {
 52→            return Ok(Self::OxfmtToml { path });
 53→        }
 54→
 55→        // Then external formatter files
 56→        // `package.json` is special: sorted then formatted
 57→        if file_name == "package.json" {
 58→            return Ok(Self::ExternalFormatterPackageJson { path, parser_name: "json-stringify" });
 59→        }
 60→
 61→        let extension = path.extension().and_then(|ext| ext.to_str());
 62→        if let Some(parser_name) = get_external_parser_name(file_name, extension) {
 63→            return Ok(Self::ExternalFormatter { path, parser_name });
 64→        }
 65→
 66→        Err(())
 67→    }
 68→}
 69→
 70→impl FormatFileStrategy {
 71→    #[cfg(not(feature = "napi"))]
 72→    pub fn can_format_without_external(&self) -> bool {
 73→        matches!(self, Self::OxcFormatter { .. } | Self::OxfmtToml { .. })
 74→    }
 75→
 76→    pub fn path(&self) -> &Path {
 77→        match self {
 78→            Self::OxcFormatter { path, .. }
 79→            | Self::OxfmtToml { path }
 80→            | Self::ExternalFormatter { path, .. }
 81→            | Self::ExternalFormatterPackageJson { path, .. } => path,
 82→        }
 83→    }
 84→
 85→    /// Resolve the stored path to an absolute path using the given `cwd`.
 86→    /// CLI file walk already provides absolute paths,
 87→    /// but stdin and NAPI entry points may receive relative paths from user input.
 88→    pub fn resolve_relative_path(mut self, cwd: &Path) -> Self {
 89→        match &mut self {
 90→            Self::OxcFormatter { path, .. }
 91→            | Self::OxfmtToml { path }
 92→            | Self::ExternalFormatter { path, .. }
 93→            | Self::ExternalFormatterPackageJson { path, .. } => {
 94→                *path = utils::normalize_relative_path(cwd, path);
 95→            }
 96→        }
 97→        self
 98→    }
 99→}
