 14→pub struct Walk {
 15→    inner: ignore::WalkParallel,
 16→}
 17→
 18→impl Walk {
 19→    pub fn build(
 20→        cwd: &Path,
 21→        paths: &[PathBuf],
 22→        ignore_paths: &[PathBuf],
 23→        with_node_modules: bool,
 24→        oxfmtrc_path: Option<&Path>,
 25→        ignore_patterns: &[String],
 26→    ) -> Result<Option<Self>, String> {
 27→        //
 28→        // Classify and normalize specified paths
 29→        //
 30→        let mut target_paths = FxHashSet::default();
 31→        let mut glob_patterns = vec![];
 32→        let mut exclude_patterns = vec![];
 33→
 34→        for path in paths {
 35→            let path_str = path.to_string_lossy();
 36→
 37→            // Instead of `oxlint`'s `--ignore-pattern=PAT`,
 38→            // `oxfmt` supports `!` prefix in paths like Prettier.
 39→            if path_str.starts_with('!') {
 40→                exclude_patterns.push(path_str.to_string());
 41→                continue;
 42→            }
 43→
 44→            // Normalize `./` prefix
 45→            let normalized =
 46→                if let Some(stripped) = path_str.strip_prefix("./") { stripped } else { &path_str };
 47→
 48→            // Separate glob patterns from concrete paths
 49→            if is_glob_pattern(normalized, cwd) {
 50→                glob_patterns.push(normalized.to_string());
 51→                continue;
 52→            }
 53→
 54→            // Resolve full path for concrete paths
 55→            let full_path = if path.is_absolute() {
 56→                path.clone()
 57→            } else if normalized == "." {
 58→                // NOTE: `.` and cwd behave differently, need to normalize
 59→                cwd.to_path_buf()
 60→            } else {
 61→                cwd.join(normalized)
 62→            };
 63→            target_paths.insert(full_path);
 64→        }
 65→
 66→        // Expand glob patterns and add to target paths
 67→        // NOTE: See `expand_glob_patterns()` for why we pre-expand globs here
 68→        if !glob_patterns.is_empty() {
 69→            target_paths.extend(expand_glob_patterns(cwd, &glob_patterns)?);
 70→        }
 71→
 72→        // Default to `cwd` if no positive paths were specified.
 73→        // Exclude patterns alone should still walk, but unmatched globs should not.
 74→        if target_paths.is_empty() && glob_patterns.is_empty() {
 75→            target_paths.insert(cwd.to_path_buf());
 76→        }
 77→
 78→        //
 79→        // Build ignores
 80→        //
 81→        // Use multiple matchers, each with correct root for pattern resolution:
 82→        // - Ignore files: root = parent directory of the ignore file
 83→        // - `.ignorePatterns`: root = parent directory of `.oxfmtrc.json`
 84→        // - Exclude paths (`!` prefix): root = cwd
 85→        //
 86→        // NOTE: Git ignore files are handled by `WalkBuilder` itself
 87→        let mut matchers: Vec<Gitignore> = vec![];
 88→
 89→        // 1. Handle formatter ignore files (`.prettierignore`, or `--ignore-path`)
 90→        // Patterns are relative to the ignore file location
 91→        for ignore_path in &load_ignore_paths(cwd, ignore_paths)? {
 92→            let (gitignore, err) = Gitignore::new(ignore_path);
 93→            if let Some(err) = err {
 94→                return Err(format!(
 95→                    "Failed to parse ignore file {}: {err}",
 96→                    ignore_path.display()
 97→                ));
 98→            }
 99→            matchers.push(gitignore);
100→        }

