 23→/// Resolve config file path from cwd and optional explicit path.
 24→pub fn resolve_oxfmtrc_path(cwd: &Path, config_path: Option<&Path>) -> Option<PathBuf> {
 25→    // If `--config` is explicitly specified, use that path
 26→    if let Some(config_path) = config_path {
 27→        return Some(utils::normalize_relative_path(cwd, config_path));
 28→    }
 29→
 30→    // If `--config` is not specified, search the nearest config file from cwd upwards
 31→    // Support both `.json` and `.jsonc`, but prefer `.json` if both exist
 32→    cwd.ancestors().find_map(|dir| {
 33→        for filename in [".oxfmtrc.json", ".oxfmtrc.jsonc"] {
 34→            let config_path = dir.join(filename);
 35→            if config_path.exists() {
 36→                return Some(config_path);
 37→            }
 38→        }
 39→        None
 40→    })
 41→}
 42→
 43→pub fn resolve_editorconfig_path(cwd: &Path) -> Option<PathBuf> {
 44→    // Search the nearest `.editorconfig` from cwd upwards
 45→    cwd.ancestors().map(|dir| dir.join(".editorconfig")).find(|p| p.exists())
 46→}
