 48→/// Resolve format options directly from a raw JSON config value.
 49→///
 50→/// This is the simplified path for the NAPI `format()` API,
 51→/// which doesn't need `.oxfmtrc` overrides, `.editorconfig`, or ignore patterns.
 52→///
 53→/// If `cwd` is provided, relative Tailwind paths are resolved against it.
 54→#[cfg(feature = "napi")]
 55→pub fn resolve_options_from_value(
 56→    raw_config: Value,
 57→    strategy: &FormatFileStrategy,
 58→    cwd: Option<&Path>,
 59→) -> Result<ResolvedOptions, String> {
 60→    let mut format_config: FormatConfig =
 61→        serde_json::from_value(raw_config).map_err(|err| err.to_string())?;
 62→    if let Some(cwd) = cwd {
 63→        format_config.resolve_tailwind_paths(cwd);
 64→    }
 65→
 66→    let mut external_options =
 67→        serde_json::to_value(&format_config).expect("FormatConfig serialization should not fail");
 68→    let oxfmt_options = format_config.into_oxfmt_options()?;
 69→
 70→    sync_external_options(&oxfmt_options.format_options, &mut external_options);
 71→
 72→    Ok(ResolvedOptions::from_oxfmt_options(oxfmt_options, external_options, strategy))
 73→}
