 76→
 77→/// Resolved options for each file type.
 78→/// Each variant contains only the options needed for that formatter.
 79→#[derive(Debug)]
 80→pub enum ResolvedOptions {
 81→    /// For JS/TS files formatted by oxc_formatter.
 82→    OxcFormatter {
 83→        format_options: Box<FormatOptions>,
 84→        /// For embedded language (xxx-in-js) formatting
 85→        external_options: Value,
 86→        /// Optional filepath override for external callbacks (e.g., Tailwind sorter).
 87→        /// When set, this path is used instead of `FormatFileStrategy::path`
 88→        /// as the `options.filepath` passed to external callbacks.
 89→        /// Needed for js-in-xxx where the strategy path is a dummy,
 90→        /// but callbacks need the parent file path to resolve their config.
 91→        filepath_override: Option<PathBuf>,
 92→        insert_final_newline: bool,
 93→    },
 94→    /// For TOML files.
 95→    OxfmtToml { toml_options: TomlFormatterOptions, insert_final_newline: bool },
 96→    /// For non-JS files formatted by external formatter (Prettier).
 97→    #[cfg(feature = "napi")]
 98→    ExternalFormatter { external_options: Value, insert_final_newline: bool },
 99→    /// For `package.json` files: optionally sorted then formatted.
100→    #[cfg(feature = "napi")]
101→    ExternalFormatterPackageJson {
102→        external_options: Value,
103→        sort_package_json: Option<sort_package_json::SortOptions>,
104→        insert_final_newline: bool,
105→    },
106→}
107→
108→impl ResolvedOptions {
109→    /// Build `ResolvedOptions` from `OxfmtOptions`, `external_options`, and `FormatFileStrategy`.
110→    ///
111→    /// This also applies plugin-specific options (Tailwind, oxfmt plugin flags) based on strategy.
112→    fn from_oxfmt_options(
113→        oxfmt_options: OxfmtOptions,
114→        mut external_options: Value,
115→        strategy: &FormatFileStrategy,
116→    ) -> Self {
117→        // Apply plugin-specific options based on strategy
118→        finalize_external_options(&mut external_options, strategy);
119→
120→        #[cfg(feature = "napi")]
121→        let OxfmtOptions { format_options, toml_options, sort_package_json, insert_final_newline } =
122→            oxfmt_options;
123→        #[cfg(not(feature = "napi"))]
124→        let OxfmtOptions { format_options, toml_options, insert_final_newline, .. } = oxfmt_options;
125→
126→        match strategy {
127→            FormatFileStrategy::OxcFormatter { .. } => ResolvedOptions::OxcFormatter {
128→                format_options: Box::new(format_options),
129→                external_options,
130→                filepath_override: None,
131→                insert_final_newline,
132→            },
133→            FormatFileStrategy::OxfmtToml { .. } => {
134→                ResolvedOptions::OxfmtToml { toml_options, insert_final_newline }
135→            }
136→            #[cfg(feature = "napi")]
137→            FormatFileStrategy::ExternalFormatter { .. } => {
138→                ResolvedOptions::ExternalFormatter { external_options, insert_final_newline }
139→            }
140→            #[cfg(feature = "napi")]
141→            FormatFileStrategy::ExternalFormatterPackageJson { .. } => {
142→                ResolvedOptions::ExternalFormatterPackageJson {
143→                    external_options,
144→                    sort_package_json,
145→                    insert_final_newline,
146→                }
147→            }
148→            #[cfg(not(feature = "napi"))]
149→            _ => {
150→                unreachable!("If `napi` feature is disabled, this should not be passed here")
151→            }
152→        }
153→    }
154→
155→    /// Set the filepath override for js-in-xxx flows.
156→    /// See [`ResolvedOptions::OxcFormatter::filepath_override`] for details.
157→    #[cfg(feature = "napi")]
158→    pub fn set_filepath_override(&mut self, filepath: PathBuf) {
159→        let ResolvedOptions::OxcFormatter { filepath_override, .. } = self else {
160→            unreachable!("`filepath_override` is only applicable for `OxcFormatter` options");
161→        };
162→        *filepath_override = Some(filepath);
163→    }
164→}
