192→    /// Create a resolver by loading config from a file path.
193→    ///
194→    /// # Errors
195→    /// Returns error if:
196→    /// - Config file is specified but not found or invalid
197→    /// - Config file parsing fails
198→    #[instrument(level = "debug", name = "oxfmt::config::from_config_paths", skip_all)]
199→    pub fn from_config_paths(
200→        cwd: &Path,

