371→            Ok(entry) => {
372→                let Some(file_type) = entry.file_type() else {
373→                    return ignore::WalkState::Continue;
374→                };
375→
376→                // Use `is_file()` to detect symlinks to the directory named `.js`
377→                #[expect(clippy::filetype_is_file)]
378→                if file_type.is_file() {
379→                    // Determine this file should be handled or NOT
380→                    // Tier 1 = `.js`, `.tsx`, etc: JS/TS files supported by `oxc_formatter`
381→                    // Tier 2 = `.toml`, etc: Some files supported by `oxfmt` directly
382→                    // Tier 3 = `.html`, `.json`, etc: Other files supported by Prettier
383→                    // (Tier 4 = `.astro`, `.svelte`, etc: Other files supported by Prettier plugins)
384→                    // Everything else: Ignored
385→                    let Ok(strategy) = FormatFileStrategy::try_from(entry.into_path()) else {
386→                        return ignore::WalkState::Continue;
387→                    };
388→
389→                    #[cfg(not(feature = "napi"))]
390→                    if !strategy.can_format_without_external() {
391→                        return ignore::WalkState::Continue;
392→                    }
393→
394→                    // Send each entry immediately through the channel
395→                    // If send fails, the receiver has been dropped, so stop walking
396→                    if self.sender.send(strategy).is_err() {
397→                        return ignore::WalkState::Quit;
398→                    }
399→                }
400→
401→                ignore::WalkState::Continue
402→            }
403→            Err(_err) => ignore::WalkState::Skip,
404→        }
405→    }
406→}
