 1→import { runCli } from "./bindings";
 2→import {
 3→  initExternalFormatter,
 4→  formatEmbeddedCode,
 5→  formatFile,
 6→  sortTailwindClasses,
 7→  disposeExternalFormatter,
 8→} from "./cli/worker-proxy";
 9→
10→// napi-JS `oxfmt` CLI entry point
11→// See also `run_cli()` function in `./src/main_napi.rs`
12→
13→void (async () => {
14→  const args = process.argv.slice(2);
15→
16→  // Node.js sets non-TTY `stdio` to non-blocking mode,
17→  // which causes `WouldBlock` errors in Rust when writing large output with `--stdin-filepath`.
18→  // https://github.com/oxc-project/oxc/issues/17939 (issue was on macOS)
19→  //
20→  // As a workaround, if used with pipe, set blocking mode before calling NAPI bindings.
21→  // See: https://github.com/napi-rs/napi-rs/issues/1630
22→  // @ts-expect-error: `_handle` is an internal API
23→  if (!process.stdout.isTTY) process.stdout._handle?.setBlocking?.(true);
24→
25→  // Call the Rust CLI first, to parse args and determine mode
26→  // NOTE: If the mode is formatter CLI, it will also perform formatting and return an exit code
27→  const [mode, exitCode] = await runCli(
28→    args,
29→    initExternalFormatter,
30→    formatEmbeddedCode,
31→    formatFile,
32→    sortTailwindClasses,
33→  );
34→
35→  // Migration modes are handled by JS
36→  if (mode === "init") {
37→    await import("./cli/migration/init").then((m) => m.runInit());
38→    return;
39→  }
40→  if (mode === "migrate:prettier") {
41→    await import("./cli/migration/migrate-prettier").then((m) => m.runMigratePrettier());
42→    return;
43→  }
44→  if (mode === "migrate:biome") {
45→    await import("./cli/migration/migrate-biome").then((m) => m.runMigrateBiome());
46→    return;
47→  }
48→
49→  // Other modes are handled by Rust, just need to set `exitCode`
50→
51→  // Clean up worker pool to not V8 crashes on process exit
52→  await disposeExternalFormatter();
53→
54→  // NOTE: It's recommended to set `process.exitCode` instead of calling `process.exit()`.
55→  // `process.exit()` kills the process immediately and `stdout` may not be flushed before process dies.
56→  // https://nodejs.org/api/process.html#processexitcode
57→  process.exitCode = exitCode!;
58→
59→  // Node.js < 25.4.0 has a race condition with ThreadsafeFunction cleanup that causes
60→  // crashes on large codebases. Add a small delay to allow pending NAPI operations
61→  // to complete before exit. Fixed in Node.js 25.4.0+.
62→  // See: https://github.com/nodejs/node/issues/55706
63→  const [major, minor] = process.versions.node.split(".").map(Number);
64→  if (major < 25 || (major === 25 && minor < 4)) {
65→    setTimeout(() => process.exit(), 50);
66→  }
67→})();
