 11→
 12→pub struct SveltePartialLoader<'a> {
 13→    source_text: &'a str,
 14→}
 15→
 16→impl<'a> SveltePartialLoader<'a> {
 17→    pub fn new(source_text: &'a str) -> Self {
 18→        Self { source_text }
 19→    }
 20→
 21→    pub fn parse(self) -> Vec<JavaScriptSource<'a>> {
 22→        self.parse_scripts()
 23→    }
 24→
 25→    /// Each *.svelte file can contain at most
 26→    ///  * one `<script>` block
 27→    ///  * one `<script context="module">` or `<script module>` block
 28→    ///    <https://github.com/sveltejs/svelte.dev/blob/ba7ad256f786aa5bc67eac3a58608f3f50b59e91/apps/svelte.dev/content/tutorial/02-advanced-svelte/08-script-module/02-module-exports/index.md>
 29→    fn parse_scripts(&self) -> Vec<JavaScriptSource<'a>> {
 30→        let mut pointer = 0;
 31→        let Some(result1) = self.parse_script(&mut pointer) else {
 32→            return vec![];
 33→        };
 34→        let Some(result2) = self.parse_script(&mut pointer) else {
 35→            return vec![result1];
 36→        };
 37→        vec![result1, result2]
 38→    }
 39→
 40→    fn parse_script(&self, pointer: &mut usize) -> Option<JavaScriptSource<'a>> {
 41→        let script_start_finder = Finder::new(SCRIPT_START);
 42→        let script_end_finder = Finder::new(SCRIPT_END);
 43→        let comment_start_finder = FinderRev::new(COMMENT_START);
 44→        let comment_end_finder: Finder<'_> = Finder::new(COMMENT_END);
 45→        // find opening "<script"
 46→        *pointer += find_script_start(
 47→            self.source_text,
 48→            *pointer,
 49→            &script_start_finder,
 50→            &comment_start_finder,
 51→            &comment_end_finder,
 52→        )?;
 53→
 54→        // find closing ">"
 55→        let offset = find_script_closing_angle(self.source_text, *pointer)?;
 56→
 57→        // get lang="ts" attribute
 58→        let content = &self.source_text[*pointer..*pointer + offset];
 59→        let is_ts = content.contains("ts");
 60→
 61→        *pointer += offset + 1;
 62→        let js_start = *pointer;
 63→
 64→        // find "</script>"
 65→        let offset = script_end_finder.find(&self.source_text.as_bytes()[*pointer..])?;
 66→        let js_end = *pointer + offset;
 67→        *pointer += offset + SCRIPT_END.len();
 68→
 69→        let source_text = &self.source_text[js_start..js_end];
 70→        let source_type = SourceType::mjs().with_typescript(is_ts);
 71→
 72→        // NOTE: loader checked that source_text.len() is less than u32::MAX
 73→        #[expect(clippy::cast_possible_truncation)]
 74→        Some(JavaScriptSource::partial(source_text, source_type, js_start as u32))
 75→    }
 76→}
