  2→use oxc_span::VALID_EXTENSIONS;
  3→
  4→use crate::loader::JavaScriptSource;
  5→
  6→mod astro;
  7→mod svelte;
  8→mod vue;
  9→pub use astro::AstroPartialLoader;
 10→pub use svelte::SveltePartialLoader;
 11→pub use vue::VuePartialLoader;
 12→
 13→const SCRIPT_START: &str = "<script";
 14→const SCRIPT_END: &str = "</script>";
 15→const COMMENT_START: &str = "<!--";
 16→const COMMENT_END: &str = "-->";
 17→
 18→/// File extensions that can contain JS/TS code in certain parts, such as in `<script>` tags, and can
 19→/// be loaded using the [`PartialLoader`].
 20→pub const LINT_PARTIAL_LOADER_EXTENSIONS: &[&str] = &["vue", "astro", "svelte"];
 21→
 22→/// All valid JavaScript/TypeScript extensions, plus additional framework files that
 23→/// contain JavaScript/TypeScript code in them (e.g., Vue, Astro, Svelte, etc.).
 24→pub const LINTABLE_EXTENSIONS: &[&str] =
 25→    constcat::concat_slices!([&str]: VALID_EXTENSIONS, LINT_PARTIAL_LOADER_EXTENSIONS);
 26→
 27→pub struct PartialLoader;
 28→
 29→impl PartialLoader {
 30→    /// Extract js section of special files.
 31→    /// Returns `None` if the special file does not have a js section.
 32→    pub fn parse<'a>(ext: &str, source_text: &'a str) -> Option<Vec<JavaScriptSource<'a>>> {
 33→        match ext {
 34→            "vue" => Some(VuePartialLoader::new(source_text).parse()),
 35→            "astro" => Some(AstroPartialLoader::new(source_text).parse()),
 36→            "svelte" => Some(SveltePartialLoader::new(source_text).parse()),
 37→            _ => None,
 38→        }
 39→    }
 40→}
 41→
 42→/// Find closing angle for situations where there is another `>` in between.
 43→/// e.g. `<script generic="T extends Record<string, string>">`
 44→/// or `<script attribute="text with > inside">`
 45→fn find_script_closing_angle(source_text: &str, pointer: usize) -> Option<usize> {
 46→    let mut open_angle = 0;
 47→    let mut in_quote: Option<char> = None;
 48→
 49→    for (offset, c) in source_text[pointer..].char_indices() {
 50→        match c {
 51→            '"' | '\'' => {
 52→                if let Some(q) = in_quote {
 53→                    if q == c {
 54→                        in_quote = None;
 55→                    }
 56→                } else {
 57→                    in_quote = Some(c);
 58→                }
 59→            }
 60→            '<' if in_quote.is_none() => {
 61→                open_angle += 1;
 62→            }
 63→            '>' if in_quote.is_none() => {
 64→                if open_angle == 0 {
 65→                    return Some(offset);
 66→                }
 67→                open_angle -= 1;
 68→            }
 69→            _ => {}
 70→        }
 71→    }
 72→
 73→    None
 74→}
 75→
 76→fn find_script_start(
 77→    source_text: &str,
 78→    pointer: usize,
 79→    script_start_finder: &Finder<'_>,
 80→    comment_start_finder: &FinderRev<'_>,
 81→    comment_end_finder: &Finder<'_>,
 82→) -> Option<usize> {
 83→    let mut new_pointer = pointer;
 84→
 85→    loop {
 86→        new_pointer +=
 87→            script_start_finder.find(&source_text.as_bytes()[new_pointer..])? + SCRIPT_START.len();
 88→
 89→        if let Some(offset) = comment_start_finder.rfind(&source_text.as_bytes()[..new_pointer]) {
 90→            if comment_end_finder
 91→                .find(&source_text.as_bytes()[offset + COMMENT_START.len()..new_pointer])
 92→                .is_some()
 93→            {
 94→                break;
 95→            }
 96→        } else {
 97→            break;
 98→        }
 99→    }
100→
101→    Some(new_pointer - pointer)
102→}
