121→
122→// ---
123→
124→/// Returns `true` if this is a TOML file.
125→fn is_toml_file(file_name: &str) -> bool {
126→    if TOML_FILENAMES.contains(file_name) {
127→        return true;
128→    }
129→
130→    #[expect(clippy::case_sensitive_file_extension_comparisons)]
131→    if file_name.ends_with(".toml.example") || file_name.ends_with(".toml") {
132→        return true;
133→    }
134→
135→    false
136→}
137→
138→static TOML_FILENAMES: phf::Set<&'static str> = phf_set! {
139→    "Pipfile",
140→    "Cargo.toml.orig",
141→};
142→
143→// ---
144→
145→/// Returns parser name for external formatter, if supported.
146→/// See also `prettier --support-info | jq '.languages[]'`
147→fn get_external_parser_name(file_name: &str, extension: Option<&str>) -> Option<&'static str> {
148→    // JSON and variants
149→    // NOTE: `package.json` is handled separately in `FormatFileStrategy::try_from()`
150→    if file_name == "composer.json" || extension == Some("importmap") {
151→        return Some("json-stringify");
152→    }
153→    if JSON_FILENAMES.contains(file_name) {
154→        return Some("json");
155→    }
156→    if let Some(ext) = extension
157→        && JSON_EXTENSIONS.contains(ext)
158→    {
159→        return Some("json");
160→    }
161→    if let Some(ext) = extension
162→        && JSONC_EXTENSIONS.contains(ext)
163→    {
164→        return Some("jsonc");
165→    }
166→    if extension == Some("json5") {
167→        return Some("json5");
168→    }
169→
170→    // YAML
171→    if YAML_FILENAMES.contains(file_name) {
172→        return Some("yaml");
173→    }
174→    if let Some(ext) = extension
175→        && YAML_EXTENSIONS.contains(ext)
176→    {
177→        return Some("yaml");
178→    }
179→
180→    // Markdown and variants
181→    if MARKDOWN_FILENAMES.contains(file_name) {
182→        return Some("markdown");
183→    }
184→    if let Some(ext) = extension
185→        && MARKDOWN_EXTENSIONS.contains(ext)
186→    {
187→        return Some("markdown");
188→    }
189→    if extension == Some("mdx") {
190→        return Some("mdx");
191→    }
192→
193→    // HTML and variants
194→    // Must be checked before generic HTML
195→    if file_name.ends_with(".component.html") {
196→        return Some("angular");
197→    }
198→    if let Some(ext) = extension
199→        && HTML_EXTENSIONS.contains(ext)
200→    {
201→        return Some("html");
202→    }
203→    if extension == Some("vue") {
204→        return Some("vue");
205→    }
206→    if extension == Some("mjml") {
207→        return Some("mjml");
208→    }
209→
210→    // CSS and variants
211→    if let Some(ext) = extension
212→        && CSS_EXTENSIONS.contains(ext)
213→    {
214→        return Some("css");
215→    }
216→    if extension == Some("less") {
217→        return Some("less");
218→    }
219→    if extension == Some("scss") {
220→        return Some("scss");
221→    }
222→
223→    // GraphQL
224→    if let Some(ext) = extension
225→        && GRAPHQL_EXTENSIONS.contains(ext)
226→    {
227→        return Some("graphql");
228→    }
229→
230→    // Handlebars
231→    if let Some(ext) = extension
232→        && HANDLEBARS_EXTENSIONS.contains(ext)
233→    {
234→        return Some("glimmer");
235→    }
236→
237→    None
238→}
