  1→/**
  2→ * API functions for Prettier integration.
  3→ *
  4→ * These must be plain functions because:
  5→ * - They can be called as `tinypool` RPC functions via `cli-worker.ts`
  6→ *   - Tinypool runs workers as `child_process`, so each worker is an isolated process
  7→ *   - Module-level caches are shared only within each worker process
  8→ * - They can also be imported directly via `index.ts` (Node.js API)
  9→ *   - In this case, module-level caches are shared globally
 10→ *
 11→ * The caches (`xxxCache`) are for lazy loading
 12→ * and avoiding redundant dynamic imports within the same process.
 13→ */
 14→
 15→import type { Options, Plugin } from "prettier";
 16→
 17→// Lazy load Prettier
 18→//
 19→// NOTE: In the past, statically importing caused issues with `oxfmt --lsp` not starting.
 20→// However, this issue has not been observed recently, possibly due to changes in the bundling configuration.
 21→// Anyway, we keep lazy loading for now to minimize initial load time.
 22→let prettierCache: typeof import("prettier");
 23→
 24→async function loadPrettier(): Promise<typeof import("prettier")> {
 25→  if (prettierCache) return prettierCache;
 26→
 27→  prettierCache = await import("prettier");
 28→  return prettierCache;
 29→}
 30→
 31→// ---
 32→
 33→/**
 34→ * TODO: Plugins support
 35→ * - Read `plugins` field
 36→ * - Load plugins dynamically and parse `languages` field
 37→ * - Map file extensions and filenames to Prettier parsers
 38→ *
 39→ * @returns Array of loaded plugin's `languages` info
 40→ */
 41→export async function resolvePlugins(): Promise<string[]> {
 42→  return [];
 43→}
 44→
 45→// ---
 46→
 47→export type FormatEmbeddedCodeParam = {
 48→  code: string;
 49→  options: Options;
 50→};
 51→
 52→/**
 53→ * Format xxx-in-js code snippets
 54→ *
 55→ * @returns Formatted code snippet
 56→ * TODO: In the future, this should return `Doc` instead of string,
 57→ * otherwise, we cannot calculate `printWidth` correctly.
 58→ */
 59→export async function formatEmbeddedCode({
 60→  code,
 61→  options,
 62→}: FormatEmbeddedCodeParam): Promise<string> {
 63→  const prettier = await loadPrettier();
 64→
 65→  // Enable Tailwind CSS plugin for embedded code (e.g., html`...` in JS) if needed
 66→  await setupTailwindPlugin(options);
 67→
 68→  // NOTE: This will throw if:
 69→  // - Specified parser is not available
 70→  // - Or, code has syntax errors
 71→  // In such cases, Rust side will fallback to original code
 72→  return prettier.format(code, options);
 73→}
 74→
 75→// ---
 76→
 77→export type FormatFileParam = {
 78→  code: string;
 79→  options: Options;
 80→};
 81→
 82→/**
 83→ * Format non-js file
 84→ *
 85→ * @returns Formatted code
 86→ */
 87→export async function formatFile({ code, options }: FormatFileParam): Promise<string> {
 88→  const prettier = await loadPrettier();
 89→
 90→  // Enable Tailwind CSS plugin for non-JS files if needed
 91→  await setupTailwindPlugin(options);
 92→  // Add oxfmt plugin for (j|t)-in-xxx files to use `oxc_formatter` instead of built-in formatter.
 93→  // NOTE: This must be last since Prettier plugins are applied in order
 94→  await setupOxfmtPlugin(options);
 95→
 96→  return prettier.format(code, options);
 97→}
 98→
 99→// ---
100→// Tailwind CSS support
101→// ---
102→
103→// Import types only to avoid runtime error if plugin is not installed
104→
105→// Shared cache for prettier-plugin-tailwindcss
106→let tailwindPluginCache: typeof import("prettier-plugin-tailwindcss");
107→
108→async function loadTailwindPlugin(): Promise<typeof import("prettier-plugin-tailwindcss")> {
109→  if (tailwindPluginCache) return tailwindPluginCache;
110→
111→  tailwindPluginCache = await import("prettier-plugin-tailwindcss");
112→  return tailwindPluginCache;
113→}
114→
115→// ---
116→
117→/**
118→ * Load Tailwind CSS plugin lazily when `options._useTailwindPlugin` flag is set.
119→ * The flag is added by Rust side only for relevant parsers.
120→ *
121→ * Option mapping (sortTailwindcss.xxx → tailwindXxx) is also done in Rust side.
122→ */
123→async function setupTailwindPlugin(options: Options): Promise<void> {
124→  if ("_useTailwindPlugin" in options === false) return;
125→
126→  const tailwindPlugin = await loadTailwindPlugin();
127→
128→  options.plugins ??= [];
129→  options.plugins.push(tailwindPlugin as Plugin);
130→}
131→
132→// ---
133→
134→export interface SortTailwindClassesArgs {
135→  classes: string[];
136→  options: {
137→    filepath?: string;
138→    tailwindStylesheet?: string;
139→    tailwindConfig?: string;
140→    tailwindPreserveWhitespace?: boolean;
141→    tailwindPreserveDuplicates?: boolean;
142→  };
143→}
144→
145→/**
146→ * Process Tailwind CSS classes found in JS/TS files in batch.
147→ * @param args - Object containing classes and options (filepath is in options.filepath)
148→ * @returns Array of sorted class strings (same order/length as input)
149→ */
150→export async function sortTailwindClasses({
151→  classes,
152→  options,
153→}: SortTailwindClassesArgs): Promise<string[]> {
154→  const { createSorter } = await import("prettier-plugin-tailwindcss/sorter");
155→
156→  const sorter = await createSorter({
157→    filepath: options.filepath,
158→    stylesheetPath: options.tailwindStylesheet,
159→    configPath: options.tailwindConfig,
160→    preserveWhitespace: options.tailwindPreserveWhitespace,
161→    preserveDuplicates: options.tailwindPreserveDuplicates,
162→  });
163→
164→  return sorter.sortClassAttributes(classes);
165→}
166→
167→// ---
168→// Oxfmt plugin support for (j|t)-in-xxx files
169→// ---
170→
171→let oxfmtPluginCache: Plugin;
172→
173→async function loadOxfmtPlugin(): Promise<Plugin> {
174→  if (oxfmtPluginCache) return oxfmtPluginCache;
175→
176→  oxfmtPluginCache = (await import("./prettier-plugin-oxfmt/index")) as Plugin;
177→  return oxfmtPluginCache;
178→}
179→
180→// ---
