115→/// Takes (options, classes) and returns sorted classes.
116→/// The `filepath` is included in `options`.
117→type TailwindWithConfigCallback = Arc<dyn Fn(&Value, Vec<String>) -> Vec<String> + Send + Sync>;
118→
119→/// External formatter that wraps a JS callback.
120→#[derive(Clone)]
121→pub struct ExternalFormatter {
122→    /// Handles to raw ThreadsafeFunctions for explicit cleanup
123→    handles: TsfnHandles,
124→    pub init: InitExternalFormatterCallback,
125→    pub format_embedded: FormatEmbeddedWithConfigCallback,
126→    pub format_file: FormatFileWithConfigCallback,
127→    pub sort_tailwindcss_classes: TailwindWithConfigCallback,
128→}
129→
130→impl std::fmt::Debug for ExternalFormatter {
131→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
132→        f.debug_struct("ExternalFormatter")
133→            .field("init", &"<callback>")
134→            .field("format_embedded", &"<callback>")
135→            .field("format_file", &"<callback>")
136→            .field("sort_tailwindcss_classes", &"<callback>")
137→            .finish()
138→    }
139→}
140→
141→impl ExternalFormatter {
142→    /// Create an [`ExternalFormatter`] from JS callbacks.
143→    ///
144→    /// The ThreadsafeFunctions are wrapped in `Arc<Mutex<Option<...>>>` to allow
145→    /// explicit cleanup via the `cleanup()` method. This prevents use-after-free
146→    /// crashes on Node.js exit when V8 cleans up global handles.
147→    pub fn new(
148→        init_cb: JsInitExternalFormatterCb,
149→        format_embedded_cb: JsFormatEmbeddedCb,
150→        format_file_cb: JsFormatFileCb,
151→        sort_tailwindcss_classes_cb: JsSortTailwindClassesCb,
152→    ) -> Self {
153→        // Wrap TSFNs in Arc<RwLock<Option<...>>> so they can be explicitly dropped
154→        let init_handle = Arc::new(RwLock::new(Some(init_cb)));
155→        let format_embedded_handle = Arc::new(RwLock::new(Some(format_embedded_cb)));
156→        let format_file_handle = Arc::new(RwLock::new(Some(format_file_cb)));
157→        let sort_tailwind_handle = Arc::new(RwLock::new(Some(sort_tailwindcss_classes_cb)));
158→
159→        // Create handles struct for cleanup
160→        let handles = TsfnHandles {
161→            init: Arc::clone(&init_handle),
162→            format_embedded: Arc::clone(&format_embedded_handle),
163→            format_file: Arc::clone(&format_file_handle),
164→            sort_tailwind: Arc::clone(&sort_tailwind_handle),
165→        };
166→
167→        let rust_init = wrap_init_external_formatter(init_handle);
168→        let rust_format_embedded = wrap_format_embedded(format_embedded_handle);
169→        let rust_format_file = wrap_format_file(format_file_handle);
170→        let rust_tailwind = wrap_sort_tailwind_classes(sort_tailwind_handle);
171→        Self {
172→            handles,
173→            init: rust_init,
174→            format_embedded: rust_format_embedded,
175→            format_file: rust_format_file,
176→            sort_tailwindcss_classes: rust_tailwind,
177→        }
178→    }
179→
180→    /// Explicitly drop all ThreadsafeFunctions to prevent use-after-free
181→    /// during V8 cleanup on Node.js exit.
182→    ///
183→    /// This should be called before the function returns to ensure the TSFNs
184→    /// are released while V8 handles are still valid.
185→    pub fn cleanup(&self) {
186→        self.handles.cleanup();
187→    }
188→
189→    /// Initialize external formatter using the JS callback.
190→    pub fn init(&self, num_threads: usize) -> Result<Vec<String>, String> {
191→        debug_span!("oxfmt::external::init", num_threads = num_threads)
192→            .in_scope(|| (self.init)(num_threads))
193→    }
194→
195→    /// Convert this external formatter to the oxc_formatter::ExternalCallbacks type.
196→    /// The options (including `filepath`) are captured in the closures and passed to JS on each call.
197→    pub fn to_external_callbacks(
198→        &self,
199→        format_options: &FormatOptions,
200→        options: Value,
201→    ) -> ExternalCallbacks {
202→        let needs_embedded = !format_options.embedded_language_formatting.is_off();
203→        let embedded_callback: Option<EmbeddedFormatterCallback> = if needs_embedded {
204→            let format_embedded = Arc::clone(&self.format_embedded);
205→            let options_for_embedded = options.clone();
206→            Some(Arc::new(move |language: &str, code: &str| {
207→                let Some(parser_name) = language_to_prettier_parser(language) else {
208→                    // NOTE: Do not return `Ok(original)` here.
209→                    // We need to keep unsupported content as-is.
210→                    return Err(format!("Unsupported language: {language}"));
211→                };
212→                debug_span!("oxfmt::external::format_embedded", parser = parser_name).in_scope(
213→                    || {
214→                        // `clone()` is unavoidable here,
215→                        // because there may be multiple embedded sections in one JS/TS file.
216→                        let mut options = options_for_embedded.clone();
217→                        if let Value::Object(ref mut map) = options {
218→                            map.insert(
219→                                "parser".to_string(),
220→                                Value::String(parser_name.to_string()),
221→                            );
222→                        }
223→                        (format_embedded)(options, code)
224→                            .map(|mut code| {
225→                                // Remove trailing newline added by Prettier without allocation
226→                                // For embedded code, we never want trailing newlines, regardless of options.
227→                                let trimmed_len = code.trim_end().len();
228→                                code.truncate(trimmed_len);
229→                                code
230→                            })
231→                            .map_err(|err| {
232→                                format!(
233→                                    "Failed to format embedded code for parser '{parser_name}': {err}"
234→                                )
235→                            })
236→                    },
237→                )
238→            }))
239→        } else {
240→            None
241→        };
242→
243→        let needs_tailwind = format_options.sort_tailwindcss.is_some();
244→        let tailwind_callback: Option<TailwindCallback> = if needs_tailwind {
245→            let sort_tailwindcss_classes = Arc::clone(&self.sort_tailwindcss_classes);
246→            Some(Arc::new(move |classes: Vec<String>| {
247→                debug_span!("oxfmt::external::sort_tailwind", classes_count = classes.len())
248→                    .in_scope(|| (sort_tailwindcss_classes)(&options, classes))
249→            }))
250→        } else {
251→            None
252→        };
253→
254→        ExternalCallbacks::new()
255→            .with_embedded_formatter(embedded_callback)
256→            .with_tailwind(tailwind_callback)
257→    }
258→
259→    /// Format non-js file using the JS callback.
260→    /// The `options` Value should already have `parser` and `filepath` set by the caller.
261→    pub fn format_file(&self, options: Value, code: &str) -> Result<String, String> {
262→        (self.format_file)(options, code)
263→    }
264→
265→    #[cfg(test)]
266→    pub fn dummy() -> Self {
267→        // Currently, LSP tests are implemented in Rust, while our external formatter relies on JS.
268→        // Therefore, just provides a dummy external formatter that consistently returns errors.
269→        Self {
270→            handles: TsfnHandles {
271→                init: Arc::new(RwLock::new(None)),
272→                format_embedded: Arc::new(RwLock::new(None)),
273→                format_file: Arc::new(RwLock::new(None)),
274→                sort_tailwind: Arc::new(RwLock::new(None)),
275→            },
276→            init: Arc::new(|_| Err("Dummy init called".to_string())),
277→            format_embedded: Arc::new(|_, _| Err("Dummy format_embedded called".to_string())),
278→            format_file: Arc::new(|_, _| Err("Dummy format_file called".to_string())),
279→            sort_tailwindcss_classes: Arc::new(|_, _| vec![]),
280→        }
281→    }
282→}
283→
284→// ---
285→
286→/// Mapping from `oxc_formatter` language identifiers to Prettier `parser` names.
287→/// This is the single source of truth for supported embedded languages.
288→fn language_to_prettier_parser(language: &str) -> Option<&'static str> {
289→    match language {
290→        // TODO: "tagged-css" should use `scss` parser to support quasis
291→        "tagged-css" | "styled-jsx" => Some("css"),
292→        "tagged-graphql" => Some("graphql"),
293→        "tagged-html" => Some("html"),
294→        "tagged-markdown" => Some("markdown"),
295→        "angular-template" => Some("angular"),
296→        "angular-styles" => Some("scss"),
297→        _ => None,
298→    }
299→}
300→
301→// ---
302→
303→// NOTE: These methods are all wrapped by `block_on` to run the async JS calls in a blocking manner.
304→//
305→// When called from `rayon` worker threads (Mode::Cli), this works fine.
306→// Because `rayon` threads are separate from the `tokio` runtime.
307→//
308→// However, in cases like `--stdin-filepath` or Node.js API calls,
309→// where already inside an async context (the `napi`'s `async` function),
310→// calling `block_on` directly would cause issues with nested async runtime access.
311→//
312→// Therefore, `block_in_place()` is used at the call site
313→// to temporarily convert the current async task into a blocking context.
314→
315→/// Wrap JS `initExternalFormatter` callback as a normal Rust function.
316→fn wrap_init_external_formatter(
317→    cb_handle: Arc<RwLock<Option<JsInitExternalFormatterCb>>>,
318→) -> InitExternalFormatterCallback {
319→    Arc::new(move |num_threads: usize| {
320→        let guard = cb_handle.read().unwrap();
321→        let Some(cb) = guard.as_ref() else {
322→            return Err("JS callback unavailable (environment shutting down)".to_string());
323→        };
324→        #[expect(clippy::cast_possible_truncation)]
325→        let result = block_on(async {
326→            let status = cb.call_async(FnArgs::from((num_threads as u32,))).await;
327→            match status {
328→                Ok(promise) => match promise.await {
329→                    Ok(languages) => Ok(languages),
330→                    Err(err) => Err(err.reason.clone()),
331→                },
332→                Err(err) => Err(err.reason.clone()),
333→            }
334→        });
335→        drop(guard);
336→        result
337→    })
338→}
339→
340→/// Wrap JS `formatEmbeddedCode` callback as a normal Rust function.
341→/// The `options` Value is received with `parser` already set by the caller.
342→fn wrap_format_embedded(
343→    cb_handle: Arc<RwLock<Option<JsFormatEmbeddedCb>>>,
344→) -> FormatEmbeddedWithConfigCallback {
345→    Arc::new(move |options: Value, code: &str| {
346→        let guard = cb_handle.read().unwrap();
347→        let Some(cb) = guard.as_ref() else {
348→            return Err("JS callback unavailable (environment shutting down)".to_string());
349→        };
350→        let result = block_on(async {
351→            let status = cb.call_async(FnArgs::from((options, code.to_string()))).await;
352→            match status {
353→                Ok(promise) => match promise.await {
354→                    Ok(formatted_code) => Ok(formatted_code),
355→                    Err(err) => Err(err.reason.clone()),
356→                },
357→                Err(err) => Err(err.reason.clone()),
358→            }
359→        });
360→        drop(guard);
361→        result
362→    })
363→}
364→
365→/// Wrap JS `formatFile` callback as a normal Rust function.
366→/// The `options` Value is received with `parser` and `filepath` already set by the caller.
367→fn wrap_format_file(
368→    cb_handle: Arc<RwLock<Option<JsFormatFileCb>>>,
369→) -> FormatFileWithConfigCallback {
370→    Arc::new(move |options: Value, code: &str| {
371→        let guard = cb_handle.read().unwrap();
372→        let Some(cb) = guard.as_ref() else {
373→            return Err("JS callback unavailable (environment shutting down)".to_string());
374→        };
375→        let result = block_on(async {
376→            let status = cb.call_async(FnArgs::from((options, code.to_string()))).await;
377→            match status {
378→                Ok(promise) => match promise.await {
379→                    Ok(formatted_code) => Ok(formatted_code),
380→                    Err(err) => Err(err.reason.clone()),
381→                },
382→                Err(err) => Err(err.reason.clone()),
383→            }
384→        });
385→        drop(guard);
386→        result
387→    })
388→}
389→
390→/// Wrap JS `sortTailwindClasses` callback as a normal Rust function.
391→fn wrap_sort_tailwind_classes(
392→    cb_handle: Arc<RwLock<Option<JsSortTailwindClassesCb>>>,
393→) -> TailwindWithConfigCallback {
394→    Arc::new(move |options: &Value, classes: Vec<String>| {
395→        let guard = cb_handle.read().unwrap();
396→        let Some(cb) = guard.as_ref() else {
397→            // Return original classes if callback unavailable
398→            return classes;
399→        };
400→        let result = block_on(async {
401→            let args = FnArgs::from((options.clone(), classes.clone()));
402→            match cb.call_async(args).await {
403→                Ok(promise) => match promise.await {
404→                    Ok(sorted) => sorted,
405→                    // Return original classes on error
406→                    Err(_) => classes,
407→                },
408→                // Return original classes on error
409→                Err(_) => classes,
410→            }
411→        });
412→        drop(guard);
413→        result
414→    })
415→}
