impl SortGroupItemConfig {
    fn into_vec(self) -> Vec<String> {
        match self {
            Self::Single(s) => vec![s],
            Self::Multiple(v) => v,
            Self::NewlinesBetween(_) => {
                unreachable!("NewlinesBetween markers should be handled before calling into_vec")
            }
        }
    }
}

