#[cfg(test)]
mod tests_sync_external_options {
    use super::*;

    #[test]
    fn test_sync_external_options_defaults() {
        let json_string = r"{}";
        let mut raw_config: Value = serde_json::from_str(json_string).unwrap();
        let config: FormatConfig = serde_json::from_str(json_string).unwrap();
        let oxfmt_options = config.into_oxfmt_options().unwrap();

        sync_external_options(&oxfmt_options.format_options, &mut raw_config);

        let obj = raw_config.as_object().unwrap();
        assert_eq!(obj.get("printWidth").unwrap(), 100);
    }

    #[test]
    fn test_sync_external_options_with_user_values() {
        let json_string = r#"{
            "printWidth": 80,
            "ignorePatterns": ["*.min.js"],
            "experimentalSortImports": { "order": "asc" }
        }"#;
        let mut raw_config: Value = serde_json::from_str(json_string).unwrap();
        let config: FormatConfig = serde_json::from_str(json_string).unwrap();
        let oxfmt_options = config.into_oxfmt_options().unwrap();

        sync_external_options(&oxfmt_options.format_options, &mut raw_config);

        let obj = raw_config.as_object().unwrap();
        // User-specified value is preserved via FormatOptions
        assert_eq!(obj.get("printWidth").unwrap(), 80);
        // oxfmt extensions are preserved (for caching)
        // They will be removed later by `finalize_external_options()`
        assert!(obj.contains_key("ignorePatterns"));
        assert!(obj.contains_key("experimentalSortImports"));
    }

    #[test]
    fn test_overrides_parsing() {
        let json = r#"{
            "tabWidth": 2,
            "overrides": [
                {
                    "files": ["*.test.js"],
                    "options": { "tabWidth": 4 }
                },
                {
                    "files": ["*.md", "*.html"],
                    "excludeFiles": ["*.min.js"],
                    "options": { "printWidth": 80 }
                }
            ]
        }"#;

        let config: Oxfmtrc = serde_json::from_str(json).unwrap();
        assert!(config.overrides.is_some());

        let overrides = config.overrides.unwrap();
        assert_eq!(overrides.len(), 2);

        // First override: single file pattern
        assert_eq!(overrides[0].files, vec!["*.test.js"]);
        assert!(overrides[0].exclude_files.is_none());
        assert_eq!(overrides[0].options.tab_width, Some(4));

        // Second override: multiple file patterns with exclude
        assert_eq!(overrides[1].files, vec!["*.md", "*.html"]);
        assert_eq!(overrides[1].exclude_files, Some(vec!["*.min.js".to_string()]));
        assert_eq!(overrides[1].options.print_width, Some(80));
    }

    #[test]
    fn test_sync_external_options_preserves_overrides() {
        let json_string = r#"{
            "tabWidth": 2,
            "overrides": [
                { "files": ["*.test.js"], "options": { "tabWidth": 4 } }
            ]
        }"#;
        let mut raw_config: Value = serde_json::from_str(json_string).unwrap();
        let oxfmtrc: Oxfmtrc = serde_json::from_str(json_string).unwrap();
        let oxfmt_options = oxfmtrc.format_config.into_oxfmt_options().unwrap();

        sync_external_options(&oxfmt_options.format_options, &mut raw_config);

        let obj = raw_config.as_object().unwrap();
        // Overrides are preserved (for caching)
        // They will be removed later by `finalize_external_options()`
        assert!(obj.contains_key("overrides"));
    }

    #[test]
    fn test_finalize_external_options_removes_oxfmt_extensions() {
        use std::path::PathBuf;

        use oxc_span::SourceType;

        let json_string = r#"{
            "tabWidth": 2,
            "overrides": [
                { "files": ["*.test.js"], "options": { "tabWidth": 4 } }
            ],
            "ignorePatterns": ["*.min.js"],
            "sortImports": { "order": "asc" }
        }"#;
        let mut raw_config: Value = serde_json::from_str(json_string).unwrap();

        let strategy = super::super::FormatFileStrategy::OxcFormatter {
            path: PathBuf::from("test.js"),
            source_type: SourceType::mjs(),
        };
        finalize_external_options(&mut raw_config, &strategy);

        let obj = raw_config.as_object().unwrap();
        // oxfmt extensions are removed by finalize_external_options
        assert!(!obj.contains_key("overrides"));
        assert!(!obj.contains_key("ignorePatterns"));
        assert!(!obj.contains_key("sortImports"));
    }

    #[test]
    #[cfg(feature = "napi")]
    fn test_finalize_external_options_sets_oxfmt_plugin_filepath() {
        use std::path::PathBuf;

        let json_string = r#"{
            "printWidth": 100,
            "singleQuote": true,
            "experimentalSortImports": { "order": "asc" }
        }"#;
        let mut raw_config: Value = serde_json::from_str(json_string).unwrap();

        let strategy = super::super::FormatFileStrategy::ExternalFormatter {
            path: PathBuf::from("/tmp/foo/bar/App.vue"),
            parser_name: "vue",
        };
        finalize_external_options(&mut raw_config, &strategy);

        let obj = raw_config.as_object().unwrap();
        let plugin_options_json = obj
            .get("_oxfmtPluginOptionsJson")
            .and_then(Value::as_str)
            .expect("Expected `_oxfmtPluginOptionsJson` to be set");

        let plugin_options: Value = serde_json::from_str(plugin_options_json).unwrap();
        let plugin_obj = plugin_options.as_object().unwrap();
        assert_eq!(
            plugin_obj.get("filepath"),
            Some(&Value::String("/tmp/foo/bar/App.vue".to_string()))
        );
    }
}

#[cfg(test)]
mod tests_json_deep_merge {
    use super::*;

    #[test]
    fn test_json_deep_merge() {
        use serde_json::json;

        // Primitives: overlay wins
        let base = json!({ "semi": true, "tabWidth": 2 });
        let overlay = json!({ "semi": false });
        let merged = json_deep_merge(base, overlay);
        assert_eq!(merged, json!({ "semi": false, "tabWidth": 2 }));

        // Nested objects: deep merge
        let base = json!({ "experimentalSortImports": { "order": "asc", "ignoreCase": true } });
        let overlay = json!({ "experimentalSortImports": { "order": "desc" } });
        let merged = json_deep_merge(base, overlay);
        assert_eq!(
            merged,
            json!({ "experimentalSortImports": { "order": "desc", "ignoreCase": true } })
        );

        // Null overwrites value (but in practice, None is skipped during serialization)
        let base = json!({ "semi": false, "tabWidth": 4 });
        let overlay = json!({ "semi": null });
        let merged = json_deep_merge(base, overlay);
        assert_eq!(merged, json!({ "semi": null, "tabWidth": 4 }));
    }
}

use std::path::{Path, PathBuf};

use phf::phf_set;

use oxc_formatter::get_supported_source_type;
use oxc_span::SourceType;

use super::utils;

pub enum FormatFileStrategy {
    OxcFormatter {
        path: PathBuf,
        source_type: SourceType,
    },
    /// TOML files formatted by taplo (Pure Rust).
    OxfmtToml {
        path: PathBuf,
    },
    ExternalFormatter {
        path: PathBuf,
        parser_name: &'static str,
    },
    /// `package.json` is special: sorted by `sort-package-json` then formatted by external formatter.
    ExternalFormatterPackageJson {
        path: PathBuf,
        parser_name: &'static str,
    },
}

impl TryFrom<PathBuf> for FormatFileStrategy {
    type Error = ();

    fn try_from(path: PathBuf) -> Result<Self, Self::Error> {
        // Check JS/TS files first
        // TODO: This logic should(can) move to this file, after LSP support is also moved here.
        if let Some(source_type) = get_supported_source_type(&path) {
            return Ok(Self::OxcFormatter { path, source_type });
        }

        // Extract file_name and extension once for all subsequent checks
        let Some(file_name) = path.file_name().and_then(|f| f.to_str()) else {
            return Err(());
        };

        // Excluded files like lock files
        if EXCLUDE_FILENAMES.contains(file_name) {
            return Err(());
        }

        // Then TOML files
        if is_toml_file(file_name) {
            return Ok(Self::OxfmtToml { path });
        }

        // Then external formatter files
        // `package.json` is special: sorted then formatted
        if file_name == "package.json" {
            return Ok(Self::ExternalFormatterPackageJson { path, parser_name: "json-stringify" });
        }

        let extension = path.extension().and_then(|ext| ext.to_str());
        if let Some(parser_name) = get_external_parser_name(file_name, extension) {
            return Ok(Self::ExternalFormatter { path, parser_name });
        }

        Err(())
    }
}

impl FormatFileStrategy {
    #[cfg(not(feature = "napi"))]
    pub fn can_format_without_external(&self) -> bool {
        matches!(self, Self::OxcFormatter { .. } | Self::OxfmtToml { .. })
    }

    pub fn path(&self) -> &Path {
        match self {
            Self::OxcFormatter { path, .. }
            | Self::OxfmtToml { path }
            | Self::ExternalFormatter { path, .. }
            | Self::ExternalFormatterPackageJson { path, .. } => path,
        }
    }

    /// Resolve the stored path to an absolute path using the given `cwd`.
    /// CLI file walk already provides absolute paths,
    /// but stdin and NAPI entry points may receive relative paths from user input.
    pub fn resolve_relative_path(mut self, cwd: &Path) -> Self {
        match &mut self {
            Self::OxcFormatter { path, .. }
            | Self::OxfmtToml { path }
            | Self::ExternalFormatter { path, .. }
            | Self::ExternalFormatterPackageJson { path, .. } => {
                *path = utils::normalize_relative_path(cwd, path);
            }
        }
        self
    }
}

static EXCLUDE_FILENAMES: phf::Set<&'static str> = phf_set! {
    // JSON, YAML lock files
    "package-lock.json",
    "pnpm-lock.yaml",
    "yarn.lock",
    "MODULE.bazel.lock",
    "bun.lock",
    "deno.lock",
    "composer.lock",
    "Package.resolved",
    "Pipfile.lock",
    "flake.lock",
    "mcmod.info",
    // TOML lock files
    "Cargo.lock",
    "Gopkg.lock",
    "pdm.lock",
    "poetry.lock",
    "uv.lock",
};

// ---

/// Returns `true` if this is a TOML file.
fn is_toml_file(file_name: &str) -> bool {
    if TOML_FILENAMES.contains(file_name) {
        return true;
    }

    #[expect(clippy::case_sensitive_file_extension_comparisons)]
    if file_name.ends_with(".toml.example") || file_name.ends_with(".toml") {
        return true;
    }

    false
}

static TOML_FILENAMES: phf::Set<&'static str> = phf_set! {
    "Pipfile",
    "Cargo.toml.orig",
};

// ---

/// Returns parser name for external formatter, if supported.
/// See also `prettier --support-info | jq '.languages[]'`
fn get_external_parser_name(file_name: &str, extension: Option<&str>) -> Option<&'static str> {
    // JSON and variants
    // NOTE: `package.json` is handled separately in `FormatFileStrategy::try_from()`
    if file_name == "composer.json" || extension == Some("importmap") {
        return Some("json-stringify");
    }
    if JSON_FILENAMES.contains(file_name) {
        return Some("json");
    }
    if let Some(ext) = extension
        && JSON_EXTENSIONS.contains(ext)
    {
        return Some("json");
    }
    if let Some(ext) = extension
        && JSONC_EXTENSIONS.contains(ext)
    {
        return Some("jsonc");
    }
    if extension == Some("json5") {
        return Some("json5");
    }

    // YAML
    if YAML_FILENAMES.contains(file_name) {
        return Some("yaml");
    }
    if let Some(ext) = extension
        && YAML_EXTENSIONS.contains(ext)
    {
        return Some("yaml");
    }

    // Markdown and variants
    if MARKDOWN_FILENAMES.contains(file_name) {
        return Some("markdown");
    }
    if let Some(ext) = extension
        && MARKDOWN_EXTENSIONS.contains(ext)
    {
        return Some("markdown");
    }
    if extension == Some("mdx") {
        return Some("mdx");
    }

    // HTML and variants
    // Must be checked before generic HTML
    if file_name.ends_with(".component.html") {
        return Some("angular");
    }
    if let Some(ext) = extension
        && HTML_EXTENSIONS.contains(ext)
    {
        return Some("html");
    }
    if extension == Some("vue") {
        return Some("vue");
    }
    if extension == Some("svelte") {
        return Some("svelte");
    }
    if extension == Some("mjml") {
        return Some("mjml");
    }

    // CSS and variants
    if let Some(ext) = extension
        && CSS_EXTENSIONS.contains(ext)
    {
        return Some("css");
    }
    if extension == Some("less") {
        return Some("less");
    }
    if extension == Some("scss") {
        return Some("scss");
    }

    // GraphQL
    if let Some(ext) = extension
        && GRAPHQL_EXTENSIONS.contains(ext)
    {
        return Some("graphql");
    }

    // Handlebars
    if let Some(ext) = extension
        && HANDLEBARS_EXTENSIONS.contains(ext)
    {
        return Some("glimmer");
    }

    None
}

